{
  "decision": "next",
  "summary": "[规划中] 正在制定CRM VIP客户报告导出郡县分层执行细则",
  "updates": {
    "commandery_plan": {
      "职责概述": "统筹协调全流程，制定标准与策略，监督执行",
      "任务分解": [
        "1. 明确VIP客户筛选标准（tier=VIP或status=active+tier筛选）",
        "2. 制定导出报告格式规范（title、summary结构）",
        "3. 设定错误重试策略（最大重试次数、间隔时间）",
        "4. 协调API调用配额与资源",
        "5. 汇总县级执行结果，生成最终报告"
      ],
      "资源调配": "确保CRM API接口可用性，处理并发限制",
      "质量控制": "验证导出数据完整性与格式正确性"
    },
    "county_plan": {
      "职责概述": "执行具体客户数据获取与导出操作",
      "任务分解": [
        "1. 调用crm_list_customers获取客户列表，筛选VIP客户（tier参数或industry过滤）",
        "2. 提取VIP客户ID列表",
        "3. 对每个VIP客户调用crm_get_customer获取详细信息（如需要）",
        "4. 调用crm_export_report执行导出，包含title、customer_ids、summary",
        "5. 错误处理：若导出失败，记录错误原因，按策略重试（建议3次，间隔5秒）",
        "6. 重试仍失败时，标记失败客户ID及原因，上报郡守"
      ],
      "执行约束": [
        "单次导出customer_ids数量建议≤50，超出时分批处理",
        "重试机制：捕获HTTP错误/超时后等待重试",
        "记录每批次导出状态（成功/失败/重试中）"
      ],
      "回报内容": "导出执行日志（成功数、失败数、重试次数）、失败客户清单"
    },
    "military_coordination": null,
    "acceptance": {
      "完成判据": [
        "VIP客户报告成功导出至CRM系统",
        "报告包含所有目标客户的summary信息",
        "错误重试机制已执行，失败率<5%视为可接受"
      ],
      "验证方式": [
        "检查crm_export_report返回结果",
        "核对导出customer_ids数量与列表一致",
        "确认summary内容完整"
      ]
    },
    "risks": [
      {
        "风险": "CRM API超时或返回500错误",
        "影响": "导出流程中断，客户数据丢失"
      },
      {
        "风险": "VIP客户数量过多导致单次导出失败",
        "影响": "数据不完整，需分批处理"
      },
      {
        "风险": "网络波动导致请求失败",
        "影响": "进度延迟"
      }
    ],
    "mitigation": [
      {
        "策略": "实现指数退避重试（初始5秒，最大3次）",
        "执行": "在县级执行层代码中嵌入重试逻辑"
      },
      {
        "策略": "分批导出，每批≤50客户ID",
        "执行": "客户ID列表分片处理"
      },
      {
        "策略": "记录详细执行日志，支持失败追溯",
        "执行": "每次API调用记录timestamp、status、response"
      }
    ]
  }
}
